#!/bin/bash
pip install reportlab Pillow
export_brand_guide_pdf --brand_name "Orcheeos" --colors "{\"primary\": \"#3d87cc\", \"secondary\": \"#b75088\", \"accent\": \"#80cc20\", \"neutral_100\": \"#f4f7f9\", \"neutral_300\": \"#d5d7d8\", \"neutral_500\": \"#8a8b8c\", \"neutral_700\": \"#585859\", \"neutral_900\": \"#1e1e1e\"}" --typography "{\"heading_font\": \"'Inter', sans-serif\", \"body_font\": \"'JetBrains Mono', 'Fira Code', monospace\", \"heading_font_name\": \"Inter\", \"body_font_name\": \"JetBrains Mono\", \"google_fonts_url\": \"https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500;600;700&display=swap\", \"type_scale\": {\"display\": \"3rem\", \"h1\": \"2rem\", \"h2\": \"1.5rem\", \"h3\": \"1.25rem\", \"h4\": \"1rem\", \"body\": \"0.875rem\", \"caption\": \"0.75rem\", \"label\": \"0.6875rem\", \"code\": \"0.8125rem\"}, \"line_heights\": {\"heading\": 1.2, \"body\": 1.6}, \"letter_spacing\": {\"heading\": \"-0.02em\", \"body\": \"0em\", \"logo_lockup\": \"0.1em\"}, \"weights\": [400, 500, 600, 700]}" --logo_paths "[\"logo.svg\", \"icons/agent_node.svg\", \"icons/code_file.svg\", \"icons/langgraph_diamond.svg\", \"icons/orchestration_gear.svg\", \"icons/study_matrix.svg\", \"icons/trace_path.svg\"]" --usage_rules "# Orcheeos Brand Usage Guidelines\n\n## Logo Lockups\n- **Primary Lockup**: Horizontal logo (logo.svg) with \"Orcheeos\" in Inter 700, letter-spacing: 0.1em\n- **Icon-Only**: Use icon from logo.svg for favicons, app icons, and small UI contexts\n- **Vertical Lockup**: Available upon request for print layouts\n- **Clear Space**: Minimum padding = logo height / 4\n- **Minimum Size**: 24px width for digital, 15mm for print\n\n## Color Usage\n- **Primary**: #3d87cc — UI controls, headers, key data points\n- **Secondary**: #b75088 — Accent lines, secondary data, hover states\n- **Accent**: #80cc20 — Alerts, active states, success indicators (use sparingly)\n- **Neutral**: Use gradients from #f4f7f9 → #1e1e1e for depth\n\n## Typography\n- **Headings**: Inter 700, letter-spacing: -0.02em\n- **Body & Code**: JetBrains Mono 500, line-height: 1.6\n- **Code Blocks**: Always use JetBrains Mono, background: #1e1e1e, text: #f4f7f9\n- **Contrast Compliance**: All text meets WCAG AA on neutral backgrounds\n\n## Icon System\n- Use icons from /icons/ directory\n- All icons are 24x24px, stroke: 1.5px, no fill\n- Use #80cc20 for active icons, #8a8b8c for disabled\n\n## Design Tone\n- Technical, cold, instrument-panel aesthetic\n- Inspired by oscilloscopes: sharp lines, grid-aligned elements, monochrome depth\n- Avoid gradients unless used as subtle depth layers\n- Never use rounded corners on core UI elements\n\n## Prohibited\n- Do not rotate, skew, or recolor logo\n- Do not use accent color (#80cc20) as background\n- Do not use serif fonts\n- Do not use drop shadows or glows" --output_path "brand-guide-orcheeos.pdf"